def fibonacci(n):
    if n < 0:
        return 0
    def _fib_pair(n):
        if n == 0:
            return (0, 1)
        a, b = _fib_pair(n >> 1)
        c = a * (2 * b - a)
        d = a * a + b * b
        if n & 1:
            return (d, c + d)
        return (c, d)
    return _fib_pair(n)[0]

def fibonacci(n):
    if n < 0:
        return 0
    if n == 0:
        return 0
    a, b = 0, 1
    bit_length = n.bit_length()
    for i in range(bit_length - 1, -1, -1):
        c = a * (2 * b - a)
        d = a * a + b * b
        if (n >> i) & 1:
            a, b = d, c + d
        else:
            a, b = c, d
    return a

def fibonacci(n):
    if n < 0:
        return 0
    if n == 0:
        return 0
    a, b = 0, 1
    bit_length = n.bit_length()
    for i in range(bit_length - 1, -1, -1):
        t = a * ((b << 1) - a)
        u = a * a + b * b
        if (n >> i) & 1:
            a, b = u, t + u
        else:
            a, b = t, u
    return a
